def compute_score() -> tuple[str, float]:
    from pptx import Presentation

    try:
        # Load the modified presentation
        prs = Presentation(modified_ppt_path)

        if len(prs.slides) == 0:
            return "No slides found in presentation", 0.0

        # Get the first slide
        first_slide = prs.slides[0]

        # Look for title in slide title placeholder or any text shape
        title_text = ""

        # Check title placeholder first
        if first_slide.shapes.title:
            title_text = first_slide.shapes.title.text.strip()

        # If no title placeholder or empty, check all text shapes
        if not title_text:
            for shape in first_slide.shapes:
                if hasattr(shape, 'text') and shape.text.strip():
                    # Look for text that might be the title (containing 'Lecture')
                    if 'Lecture' in shape.text:
                        title_text = shape.text.strip()
                        break

        if not title_text:
            return "No title text found on first slide", 0.0

        # Check if title contains 'Lecture 1'
        if 'Lecture 1' in title_text:
            # Also verify it doesn't still contain 'Lecture 3'
            if 'Lecture 3' in title_text:
                return f"Title still contains 'Lecture 3': {title_text}", 0.0
            return f"Title correctly updated to contain 'Lecture 1': {title_text}", 1.0
        elif 'Lecture 3' in title_text:
            return f"Title still contains 'Lecture 3' instead of 'Lecture 1': {title_text}", 0.0
        else:
            return f"Title does not contain 'Lecture 1': {title_text}", 0.0

    except Exception as e:
        return f"Error checking presentation title: {str(e)}", 0.0

def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    import re

    try:
        # Check for extraneous changes using the diff data
        issues = []

        # Check for animation changes
        if ppt_diff.added_animations or ppt_diff.removed_animations or ppt_diff.modified_animations:
            issues.append(f"Unexpected animation changes: {len(ppt_diff.added_animations)} added, {len(ppt_diff.removed_animations)} removed, {len(ppt_diff.modified_animations)} modified")

        # Check for transition changes
        if ppt_diff.added_transitions or ppt_diff.removed_transitions or ppt_diff.modified_transitions:
            issues.append(f"Unexpected transition changes: {len(ppt_diff.added_transitions)} added, {len(ppt_diff.removed_transitions)} removed, {len(ppt_diff.modified_transitions)} modified")

        # Check for slide structure changes
        if ppt_diff.added_slides or ppt_diff.removed_slides:
            issues.append(f"Unexpected slide structure changes: {len(ppt_diff.added_slides)} added, {len(ppt_diff.removed_slides)} removed")

        # Check for slide metadata changes that aren't related to our task
        for old_slide, new_slide in ppt_diff.modified_slides:
            # Allow title changes on first slide (slide_number 1) and notes changes for footers
            if old_slide.slide_number == 1:
                # Title change is expected on first slide
                if old_slide.layout_type != new_slide.layout_type or old_slide.element_count != new_slide.element_count:
                    issues.append(f"Unexpected changes to slide 1 layout or element count")
            else:
                # For other slides, only footer-related changes should be allowed
                if (old_slide.title != new_slide.title or 
                    old_slide.layout_type != new_slide.layout_type or 
                    old_slide.element_count != new_slide.element_count):
                    issues.append(f"Unexpected changes to slide {old_slide.slide_number} beyond footer updates")

        # Additional check: Load both presentations and verify only expected text changes
        try:
            original_prs = Presentation(original_ppt_path)
            modified_prs = Presentation(modified_ppt_path)

            if len(original_prs.slides) != len(modified_prs.slides):
                issues.append("Number of slides changed unexpectedly")
            else:
                # Check each slide for unexpected text changes
                for i in range(len(original_prs.slides)):
                    orig_slide = original_prs.slides[i]
                    mod_slide = modified_prs.slides[i]

                    # Get all text from both slides
                    orig_texts = []
                    mod_texts = []

                    for shape in orig_slide.shapes:
                        if hasattr(shape, 'text'):
                            orig_texts.append(shape.text)

                    for shape in mod_slide.shapes:
                        if hasattr(shape, 'text'):
                            mod_texts.append(shape.text)

                    # For first slide, allow Lecture 3 -> Lecture 1 changes
                    if i == 0:
                        orig_combined = ' '.join(orig_texts)
                        mod_combined = ' '.join(mod_texts)

                        # Replace expected changes and see if anything else changed
                        normalized_orig = re.sub(r'Lecture\s*3', 'Lecture 1', orig_combined)
                        if normalized_orig != mod_combined:
                            # Check if it's just whitespace or minor formatting
                            if normalized_orig.replace(' ', '').replace('\n', '') != mod_combined.replace(' ', '').replace('\n', ''):
                                issues.append(f"Unexpected text changes on slide 1 beyond lecture number")

                    # For other slides, allow Lec 3.X -> Lec 1.X changes
                    else:
                        orig_combined = ' '.join(orig_texts)
                        mod_combined = ' '.join(mod_texts)

                        # Replace expected footer changes
                        normalized_orig = re.sub(r'Lec\s*3\.(\d+)', r'Lec 1.\1', orig_combined)
                        if normalized_orig != mod_combined:
                            # Check if it's just whitespace or minor formatting
                            if normalized_orig.replace(' ', '').replace('\n', '') != mod_combined.replace(' ', '').replace('\n', ''):
                                issues.append(f"Unexpected text changes on slide {i+1} beyond footer updates")

        except Exception as e:
            issues.append(f"Could not verify text changes: {str(e)}")

        if not issues:
            return "No extraneous changes detected - only intended lecture number updates made", 1.0
        else:
            # Return partial score based on severity
            severity_score = max(0.0, 1.0 - (len(issues) * 0.3))  # Deduct 0.3 per issue
            return f"Extraneous changes detected: {'; '.join(issues[:2])}{'...' if len(issues) > 2 else ''}", severity_score

    except Exception as e:
        return f"Error checking for extraneous changes: {str(e)}", 0.5
